'use client'

import { useEffect } from 'react'
import jsPDF from "jspdf"
import autoTable from "jspdf-autotable"
import { Button } from "@/components/ui/button"
import { Download, X } from "lucide-react"

interface InvoicePreviewProps {
  invoice: any
  autoDownload?: boolean
  onClose: () => void
}

const SALON_LOGO_BASE64 = "data:image/png;base64,"

const SALON_INFO = {
  name: "Syncbase",
  address: [
    "Nagpal Towers",
    "Abids",
    "Hyderabad,Telangana, India - 500001",
    "Contact - +91 9182037460   Email - info@syncbase.in"
  ]
}

export default function InvoicePreview({ invoice, autoDownload, onClose }: InvoicePreviewProps) {

  useEffect(() => {
    if (autoDownload) {
      downloadPDF()
    }
  }, [autoDownload])

  const downloadPDF = () => {
    const doc = new jsPDF("p", "mm", "a4")

    /* ---------------- HEADER ---------------- */
    if (SALON_LOGO_BASE64) {
      doc.addImage(SALON_LOGO_BASE64, "PNG", 14, 12, 34, 18)
    }

    doc.setFont("helvetica", "bold")
    doc.setFontSize(16)
    doc.text(SALON_INFO.name, 105, 14, { align: "center" })

    doc.setFont("helvetica", "normal")
    doc.setFontSize(9)
    SALON_INFO.address.forEach((line, i) => {
      doc.text(line, 105, 20 + i * 4, { align: "center" })
    })

    /* ----------- DIVIDER LINE ----------- */
    doc.line(14, 46, 196, 46)

    /* ----------- INVOICE TITLE ----------- */
    doc.setFont("helvetica", "bold")
    doc.setFontSize(18)
    doc.text("INVOICE", 105, 60, { align: "center" })

    /* ----------- INVOICE META (BELOW LINE) ----------- */
    doc.setFontSize(10)
    doc.setFont("helvetica", "normal")
    doc.text(`Invoice No: ${invoice.invoiceNo}`, 14, 70)
    doc.text(`Date: ${invoice.invoiceDate?.slice(0, 10)}`, 14, 76)

    /* ----------- BILL TO (LOWER CENTERED) ----------- */
    doc.setFontSize(11)
    doc.setFont("helvetica", "bold")
    doc.text("Bill To:", 14, 90)

    doc.setFont("helvetica", "normal")
    doc.text(invoice.clientName || "", 14, 96)
    doc.text(invoice.clientAddress || "", 14, 102)
    doc.text(invoice.clientContact || "", 14, 108)

    /* ---------------- TABLE ---------------- */
    const tableBody = invoice.items.map((item: any) => [
      item.description,
      item.quantity,
      `Rs. ${Number(item.rateInr).toFixed(2)}`,
      `Rs. ${Number(item.amountInr).toFixed(2)}`
    ])

    autoTable(doc, {
      startY: 120,
      head: [["Description", "Qty", "Rate", "Amount"]],
      body: tableBody,
      theme: "grid",
      styles: {
        fontSize: 11,
        cellPadding: 4,
        lineWidth: 0.3,
        lineColor: [0, 0, 0],
      },
      headStyles: {
        fillColor: [0, 0, 0],
        textColor: 255,
        fontStyle: "bold",
        halign: "center",
      },
      columnStyles: {
        0: { cellWidth: 80 },
        1: { halign: "center", cellWidth: 20 },
        2: { halign: "right", cellWidth: 40 },
        3: { halign: "right", cellWidth: 40 },
      }
    })

    /* ---------------- TOTALS ---------------- */
    const finalY = (doc as any).lastAutoTable.finalY + 8

    doc.setFont("helvetica", "bold")
    doc.text("Subtotal:", 140, finalY)
    doc.text(`Rs. ${Number(invoice.subtotalInr).toFixed(2)}`, 196, finalY, { align: "right" })

    doc.text("Total:", 140, finalY + 8)
    doc.text(`Rs. ${Number(invoice.totalInr).toFixed(2)}`, 196, finalY + 8, { align: "right" })

    /* ---------------- FOOTER ---------------- */
    doc.setFontSize(10)
    doc.setFont("helvetica", "italic")
    doc.text("THANK YOU FOR VISITING SYNCBASE", 105, 287, { align: "center" })

    doc.save(`${invoice.invoiceNo}.pdf`)
  }

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-lg max-w-3xl w-full p-6 shadow-lg">

        <div className="flex items-center justify-between mb-4">
          <h2 className="text-2xl font-bold">Invoice Preview</h2>

          <div className="flex gap-2">
            <Button onClick={downloadPDF} className="gap-2">
              <Download className="w-4 h-4" />
              Download PDF
            </Button>

            <Button onClick={onClose} variant="ghost">
              <X className="w-4 h-4" />
            </Button>
          </div>
        </div>

        <div className="text-sm space-y-1">
          <p><strong>Invoice:</strong> {invoice.invoiceNo}</p>
          <p><strong>Client:</strong> {invoice.clientName}</p>

          {invoice.items?.length > 0 && (
            <p>
              <strong>Served by:</strong>{" "}
              {[...new Set(invoice.items.map((i: any) => i.staffName))]
                .filter(Boolean)
                .join(", ")}
            </p>
          )}

          <p><strong>Total:</strong> Rs. {invoice.totalInr}</p>
        </div>



      </div>
    </div>
  )
}
